code.C++:
int maxNestingDepth(const string &s) {
    int maxDepth = 0, currentDepth = 0;
    for (char ch : s) {
        if (ch == '(') ++currentDepth;
        else if (ch == ')') --currentDepth;
        if (currentDepth > maxDepth) maxDepth = currentDepth;
    }
    return maxDepth;
}

