code.C:
int maxNestingDepth(const char *s) {
    int maxDepth = 0, currentDepth = 0;
    for (int i = 0; s[i] != '\0'; i++) {
        if (s[i] == '(') currentDepth++;
        else if (s[i] == ')') currentDepth--;
        if (currentDepth > maxDepth) maxDepth = currentDepth;
    }
    return maxDepth;
}

