private static int maxNestingDepth(String s) {
        int maxDepth = 0;
        int currentDepth = 0;

        for (char ch : s.toCharArray()) {
            if (ch == '(') {
                currentDepth++;
                if (currentDepth > maxDepth) {
                    maxDepth = currentDepth;
                }
            } else if (ch == ')') {
                currentDepth--;
            }
        }

        return maxDepth;
    }

